import React, { useState, useEffect } from 'react';
import axios from 'axios';
import BookList from './BookList';
import BookDetails from './BookDetails';


// Base URL for the backend API
const API_URL = 'http://localhost:3000';

function App() {
  // State for the currently displayed book and all books
  const [books, setBooks] = useState([]);
  const [selectedBookId, setSelectedBookId] = useState(null);

  // Fetch all books when the component mounts
  useEffect(() => {
    fetchBooks();
  }, []);

  const fetchBooks = async () => {
    try {
      const response = await axios.get(`${API_URL}/books`);
      setBooks(response.data);
    } catch (error) {
      console.error('Error fetching books:', error);
    }
  };

  const handleSelectBook = (id) => {
    setSelectedBookId(id);
  };

  const handleBack = () => {
    setSelectedBookId(null);
  };

  // Conditionally render BookList or BookDetails based on selectedBookId
  if (selectedBookId) {
    return <BookDetails bookId={selectedBookId} onBack={handleBack} api_url={API_URL} />;
  }

  return <BookList books={books} onSelectBook={handleSelectBook} />;
}

export default App;
